class Solution(object):
    def maximumValueSum(self, board):
        """
        :type board: List[List[int]]
        :rtype: int
        """
        m, n = len(board), len(board[0])

        # Find top 3 values in each row
        row_tops = []
        for i in range(m):
            tops = sorted(enumerate(board[i]), key=lambda x: -x[1])[:3]
            row_tops.append(tops)

        max_sum = float('-inf')

        # Strategy: pick one row, pick one column from that row
        # Then find best 2 positions from other rows that don't use that column

        for first_row in range(m):
            for first_col, first_val in row_tops[first_row]:
                # Now find best 2 positions from other rows, avoiding first_col
                # Collect all (value, col, row) tuples from other rows
                candidates = []
                for row in range(m):
                    if row == first_row:
                        continue
                    for col, val in row_tops[row]:
                        if col != first_col:
                            candidates.append((val, col, row))

                # Sort by value descending
                candidates.sort(reverse=True)

                # Find best pair with different columns
                if len(candidates) >= 2:
                    for i in range(len(candidates)):
                        for j in range(i + 1, len(candidates)):
                            val_i, col_i, row_i = candidates[i]
                            val_j, col_j, row_j = candidates[j]

                            if col_i != col_j and row_i != row_j:
                                current_sum = first_val + val_i + val_j
                                max_sum = max(max_sum, current_sum)
                                break  # Found best pair for this i

                        if max_sum > float('-inf'):
                            break  # Already found best pair

        return max_sum
